 def blocked_dependents(manifest: dict[str, Any], ticket_id: str) -> list[dict[str, Any]]:
     tickets = manifest.get("tickets") if isinstance(manifest.get("tickets"), list) else []
     blocked: list[dict[str, Any]] = []
